import java.io.File;
import java.util.Scanner;

public class SecurePathTraversalExample {
    private static final String BASE_DIRECTORY = "/path/to/directory/";

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter file name:");
        String fileName = scanner.nextLine();

        if (isValidFileName(fileName)) {
            String filePath = BASE_DIRECTORY + fileName;
            File file = new File(filePath);

            if (file.exists() && file.getAbsolutePath().startsWith(BASE_DIRECTORY)) {
                System.out.println("File exists!");
            } else {
                System.out.println("File does not exist or access is restricted.");
            }
        } else {
            System.out.println("Invalid file name.");
        }

        scanner.close();
    }

    private static boolean isValidFileName(String fileName) {
        // Implement your validation logic here
        // For example, check for allowed characters or patterns
        return fileName.matches("[a-zA-Z0-9._-]+");
    }
}

